#include<bits/stdc++.h>
#define getvis(x) (x>65535?vis[x]:vis1[x])
#define getsum(x) (x>65535?sum[x]:sum1[x])
using namespace std;
typedef unsigned long long ull;
unordered_map<ull,ull> sum;
unordered_set<ull> s,vis;
ull n,m,N,ans=0,sum1[66666],OP[300010],X[300010];
char vis1[66666];
ull calc(ull x)
{
    ull tmp=N-(__lg(x));
    return ((1ull<<tmp)-1);
}
ull read()
{
    ull x=0;
    char ch=getchar();
    while(!isdigit(ch))
    {
        ch=getchar();
    }
    while(isdigit(ch))
    {
        x=(x<<3)+(x<<1)+(ch-'0');
        ch=getchar();
    }
    return x;
}
int main()
{
    n=read(),m=read();
    sum.reserve(n*m);
    N=n;
    n=(1ull<<n)-1;
    for(ull i=1;i<=m;i++)
    {
    	OP[i]=read(),X[i]=read();
    	if(OP[i]==1)
		{
			s.insert(X[i]);
		}
	}
    for(ull i=1;i<=m;i++)
    {
        ull op=OP[i],x=X[i];
        if(op==1)
        {
            if(vis.find(x)!=vis.end()||x==1)
            {
                continue;
            }
            if(!getsum(x))
            {
                getsum(x)=calc(x);
            }
            ull s=getsum(x),tmp=x;
            while(x)
            {
                if(vis.find(x)!=vis.end()||x==1)
                {
                    break;
                }
                x>>=1;
				if(::s.find(x)!=::s.end())
				{
	                if(!getsum(x))
	                {
	                    getsum(x)=calc(x);
	                }
	                getsum(x)-=s;
				}
            }
            vis.insert(tmp);
        }
        else
        {
            while(x)
            {
                if(vis.find(x)!=vis.end()||x==1)
                {
                    break;
                }
                x>>=1;
            }
            if(!getsum(x))
            {
                getsum(x)=calc(x);
            }
            ans^=getsum(x);
        }
    }
    printf("%llu",ans);
    return 0;
}
